        val endLeaf = nextLeaf { it.textContains('\n') }

        val sb = StringBuilder()
        sb.append(
            if (startLeaf.textContains('\n')) {
                startLeaf.text.substringAfterLast('\n')
            } else {
                startLeaf.text
            },
        )

        var leaf = startLeaf.nextLeaf()
        while (leaf != null && leaf != endLeaf) {
            sb.append(leaf.text)
            leaf = leaf.nextLeaf()
        }
        if (endLeaf != null) {
            sb.append(endLeaf.text.substringBefore('\n'))
        }
        return sb.toString()
    }

